def solve(nums: list[int]) -> int:
    """
    Returns the minimum absolute difference between indices i and j such that 
    nums[i] == 1 and nums[j] == 2. Returns -1 if no such pair exists.
    """
    indices_of_1 = []
    indices_of_2 = []

    # 1. Collect indices for 1s and 2s
    for i, num in enumerate(nums):
        if num == 1:
            indices_of_1.append(i)
        elif num == 2:
            indices_of_2.append(i)

    # 2. Check if valid pairs can exist
    if not indices_of_1 or not indices_of_2:
        return -1

    # 3. Find the minimum absolute difference
    min_diff = float('inf')

    for i in indices_of_1:
        for j in indices_of_2:
            diff = abs(i - j)
            if diff < min_diff:
                min_diff = diff

    return int(min_diff)
